#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long total = 0;
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &a[i]);
            total += a[i];
        }
        long long pref = 0;
        long long ans = total; // worst case
        // consider split before first element (i=0)
        ans = total; // max(0,total)
        for (int i = 0; i < N; ++i) {
            pref += a[i];
            long long cur = pref > (total - pref) ? pref : (total - pref);
            if (cur < ans) ans = cur;
        }
        printf("%lld\n", ans);
        free(a);
    }
    return 0;
}

